function solve(grid, k) {
    let count = 0;
    let m = grid.length;
    if (m === 0) return 0;
    let n = grid[0].length;
    const directions = [ [-1,0], [1,0], [0,-1], [0,1] ];
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] !== 0) {
                let queue = [ [i, j] ];
                let sumIsland = grid[i][j];
                grid[i][j] = 0;
                while (queue.length > 0) {
                    let [x, y] = queue.shift();
                    for (let [dx, dy] of directions) {
                        let nx = x + dx;
                        let ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] !== 0) {
                            sumIsland += grid[nx][ny];
                            grid[nx][ny] = 0;
                            queue.push([nx, ny]);
                        }
                    }
                }
                if (sumIsland % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
