function solve(grid, k) {
    let count = 0;
    const m = grid.length;
    if (m === 0) return 0;
    const n = grid[0].length;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] !== 0) {
                const queue = [[i, j]];
                let sumIsland = grid[i][j];
                grid[i][j] = 0;
                while (queue.length > 0) {
                    const [x, y] = queue.shift();
                    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];
                    for (const [dx, dy] of directions) {
                        const nx = x + dx;
                        const ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] !== 0) {
                            sumIsland += grid[nx][ny];
                            grid[nx][ny] = 0;
                            queue.push([nx, ny]);
                        }
                    }
                }
                if (sumIsland % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
