                queue = deque()
                queue.append((i, j))
                sum_island = grid[i][j]
                grid[i][j] = 0
                while queue:
                    x, y = queue.popleft()
                    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
