                        if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] != 0:
                            sum_island += grid[nx][ny]
                            grid[nx][ny] = 0
                            queue.append((nx, ny))
                if sum_island % k == 0:
                    count += 1
    return count
